package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.SupWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

@Slf4j
public class BerekenBvToevalligeVergoedingen extends AbstractBerekenBv {

    public BerekenBvToevalligeVergoedingen(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        initFiscaleConstanten(RekenTijd.setIsAchterstal(rekenTijd, false));
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY) && BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvToevalligeVergoedingen(opdrachtContext, opdracht, rekenTijd, regulManager);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBvToevalligeVergoedingen(RekenContext opdrachtContext, Opdracht opdracht, RekenTijd rekenTijd, RegulManager regulManager) {
        LoonElementManager manager = opdrachtContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
        RekenBvKey bvKey;
        RekenBbKey bbKey;
        if (rekenTijd.isAchterstal) {
            bvKey = BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY;
            bbKey = BELASTBAAR_ACHTERSTAL_KEY;
        } else {
            bvKey = BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY;
            bbKey = BELASTBAAR_KEY;
        }
        Money belastbaar = getBelastbaar(bvKey, bbKey, opdrachtElementen);
        log.debug("belastbaar:{}", belastbaar);
        if (belastbaar.signum() != 0) {
            Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            Money bedrijfsvoorheffing = berekenBvToevalligeVergoedingen(belastbaar, opperLaatsteGegevens, rekenTijd, regulManager);
            herverdeelBedrijfsvoorheffing(bvKey, bedrijfsvoorheffing, bbKey, belastbaar, opdrachtElementen);
        }
        log.trace("opdrachtElementen:{}", opdrachtElementen);
    }

    private Money berekenBvToevalligeVergoedingen(Money belastbaar, Opper opperLaatsteGegevens, RekenTijd rekenTijd, RegulManager regulManager) {
        Money bedrijfsvoorheffing = Money.ZERO;
        SupWrkwBv fiscaleWerkwijze = opperLaatsteGegevens.getOpdrachtFiscaliteit().getWerkwijzeSupplement();
        log.debug("{};fiscaleWerkwijze:{}", LogTools.toSimpleLog(opperLaatsteGegevens.getOpdracht()), fiscaleWerkwijze);
        switch (fiscaleWerkwijze) {
            case BAREMA_INV_PVH:
            case BAREMA_GN_KUMUL:
                bedrijfsvoorheffing = berekenToevalligeVergoedingenBarema(belastbaar, rekenTijd);
                break;
            case PERCENTAGE:
                BigDecimal percentage = opperLaatsteGegevens.getOpdrachtFiscaliteit().getPercentageSupplement().movePointLeft(2);
                log.debug("percentage:{}", percentage);
                bedrijfsvoorheffing = belastbaar.multiply(percentage).round(2);
                break;
            case BEDRAG:
                bedrijfsvoorheffing = opperLaatsteGegevens.getOpdrachtFiscaliteit().getBedragSupplement();
                break;
            default:
                regulManager.doRegulException(opperLaatsteGegevens.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

}
